function esc(s) { return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;"); }

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function generateHTML(c) {
  return `<!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>${esc(c.titles[0])}</title><link href="https://fonts.googleapis.com/css2?family=Press+Start+2P&display=swap" rel="stylesheet"><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:"Press Start 2P",monospace;min-height:100vh;display:flex;align-items:center;justify-content:center;background:url("${c.style.background}") center/cover fixed;color:#fff;padding:20px}body::before{content:"";position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.7);z-index:-1}.container{background:rgba(0,0,0,0.85);border-radius:16px;padding:40px;max-width:800px;width:100%;box-shadow:0 0 30px ${c.style.primaryColor}40;border:2px solid ${c.style.primaryColor}}.title{text-align:center;margin-bottom:30px;font-size:14px;color:${c.style.primaryColor};text-shadow:0 0 10px ${c.style.primaryColor};min-height:1.5em}.title-text{display:inline-block;transition:opacity 0.5s ease,transform 0.5s ease}.title-text.fade-out{opacity:0;transform:translateY(-10px)}.title-text.fade-in{opacity:1;transform:translateY(0)}.btn{width:100%;padding:15px;border:none;border-radius:8px;background:linear-gradient(135deg,${c.style.primaryColor},${c.style.primaryColor}aa);color:#1a1a2e;font-family:inherit;font-size:12px;cursor:pointer;transition:all .3s;margin-top:20px}.btn:hover{transform:translateY(-2px)}.btn:disabled{background:#333;color:#666;cursor:not-allowed}.hidden{display:none}.input-group{margin-bottom:20px}.input-group label{display:block;margin-bottom:8px;font-size:10px;color:#aaa}.input-group input,.input-group textarea{width:100%;padding:15px;border:2px solid #333;border-radius:8px;background:rgba(255,255,255,.1);color:#fff;font-family:inherit;font-size:12px}.info-box{margin-top:30px;font-size:8px;color:#888;line-height:2}.progress-bar{background:#333;border-radius:10px;height:20px;margin-bottom:20px}.progress-fill{background:${c.style.primaryColor};height:100%;transition:width .3s;display:flex;align-items:center;justify-content:center;font-size:8px;color:#1a1a2e}.timer{text-align:center;font-size:20px;color:#ff6b6b;margin-bottom:20px}.timer.warning{animation:pulse .5s infinite}@keyframes pulse{0%,100%{opacity:1}50%{opacity:.5}}.question-box{background:rgba(255,255,255,.05);border-radius:12px;padding:20px;margin-bottom:20px}.question-num{font-size:10px;color:#888;margin-bottom:10px}.question-text{font-size:12px;line-height:1.8;margin-bottom:20px}.options{display:flex;flex-direction:column;gap:10px}.option{background:rgba(255,255,255,.1);border:2px solid #333;border-radius:8px;padding:15px;cursor:pointer;transition:all .2s;font-size:10px}.option:hover{border-color:${c.style.primaryColor}}.option.selected{border-color:${c.style.primaryColor};background:rgba(0,255,136,.2)}.option.correct{border-color:#00ff88;background:rgba(0,255,136,.3)}.option.wrong{border-color:#ff6b6b;background:rgba(255,107,107,.3)}.result-box{text-align:center;padding:40px}.score{font-size:48px;color:${c.style.primaryColor};margin:20px 0}.score.failed{color:#ff6b6b}.password-display{font-size:18px;text-align:center;padding:20px;background:rgba(0,255,136,.1);border-radius:8px;margin:20px 0;letter-spacing:3px;color:${c.style.primaryColor}}.stats{font-size:10px;color:#888;margin-top:20px;line-height:2;text-align:left}.stats-row{margin-bottom:15px;padding-bottom:15px;border-bottom:1px solid #333}.stats-row:last-child{border-bottom:none}.promise-answer{background:rgba(0,255,136,.1);padding:15px;border-radius:8px;margin-top:10px;font-size:10px;color:#fff;word-break:break-all}.type-badge{display:inline-block;padding:2px 8px;border-radius:4px;font-size:8px;margin-left:10px}.type-single{background:#3498db}.type-multiple{background:#e74c3c}</style></head><body><div class="container"><div id="startPage"><h1 class="title"><span class="title-text fade-in" id="titleText">${esc(c.titles[0])}</span></h1><div class="input-group"><label>联系方式</label><input type="text" id="contact" placeholder="QQ/微信/邮箱"></div><div class="input-group"><label>游戏名</label><input type="text" id="gameName" placeholder="你的游戏ID"></div><button class="btn" onclick="startQuiz()">开始答题</button><div class="info-box"><p>基础选择题: ${c.quiz.basicCount} 道</p><p>规则理解题: ${c.quiz.ruleCount} 道</p><p>承诺题: 1 道 (不计分)</p><p>时间限制: ${Math.floor(c.quiz.timeLimit/60)} 分钟</p><p>通过分数: ${c.quiz.passRate}%</p><p style="color:#e74c3c;margin-top:10px;">⚠️ 包含多选题，请仔细审题</p></div></div><div id="quizPage" class="hidden"><h1 class="title">答题中</h1><div class="timer" id="timer">${Math.floor(c.quiz.timeLimit/60)}:00</div><div class="progress-bar"><div class="progress-fill" id="progress" style="width:0%">0/${c.quiz.basicCount + c.quiz.ruleCount + 1}</div></div><div class="question-box"><div class="question-num" id="questionNum">第 1 题</div><div class="question-text" id="questionText">加载中...</div><div class="options" id="options"></div></div><button class="btn" id="nextBtn" onclick="nextQuestion()" disabled>下一题</button></div><div id="resultPage" class="hidden"><div class="result-box"><h1 class="title">答题结果</h1><div class="score" id="score">0%</div><div id="passwordBox" class="hidden"><div class="password-display" id="password"></div></div><div class="stats" id="stats"></div><button class="btn" onclick="location.reload()">重新答题</button></div></div></div><script>function esc(s){return String(s).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}var CONFIG=${JSON.stringify(c)};var TITLES=${JSON.stringify(c.titles)};var titleIdx=0,Q=[],cur=0,corr=0,sel=[],TL=${c.quiz.timeLimit},tmr=null,startTime=null,endTime=null,contact="",gameName="",promiseAnswer="";setInterval(function(){var el=document.getElementById("titleText");el.classList.remove("fade-in");el.classList.add("fade-out");setTimeout(function(){titleIdx=(titleIdx+1)%TITLES.length;el.textContent=TITLES[titleIdx];el.classList.remove("fade-out");el.classList.add("fade-in")},500)},3000);function startQuiz(){contact=document.getElementById("contact").value.trim()||"未填写";gameName=document.getElementById("gameName").value.trim()||"未填写";startTime=new Date();document.getElementById("startPage").classList.add("hidden");document.getElementById("quizPage").classList.remove("hidden");fetch("/api/quiz/start").then(r=>r.json()).then(d=>{Q=d.questions;showQuestion();startTimer()}).catch(e=>{alert("网络错误");location.reload()})}function showQuestion(){var q=Q[cur];var total=Q.length;var isMultiple=q.type==="multiple";var typeLabel=isMultiple?"【多选】":"【单选】";document.getElementById("questionNum").innerHTML="第 "+(cur+1)+" 题 / 共 "+total+" 题"+(cur===total-1?" (承诺题)":"")+"<span class='type-badge "+(isMultiple?"type-multiple":"type-single")+"'>"+typeLabel+"</span>";document.getElementById("questionText").textContent=q.question;var opts=document.getElementById("options");opts.innerHTML="";if(q.type==="promise"){var ta=document.createElement("textarea");ta.id="promiseInput";ta.style.cssText="width:100%;height:120px;padding:15px;border:2px solid #333;border-radius:8px;background:rgba(255,255,255,.1);color:#fff;font-family:inherit;font-size:12px;resize:vertical";ta.placeholder=q.placeholder||"请输入你的承诺...";ta.oninput=function(){promiseAnswer=this.value;document.getElementById("nextBtn").disabled=!this.value.trim()};opts.appendChild(ta);document.getElementById("nextBtn").textContent="提交";document.getElementById("nextBtn").disabled=true}else{q.options.forEach(function(o,i){var div=document.createElement("div");div.className="option";div.textContent=String.fromCharCode(65+i)+". "+o;div.onclick=function(){selectOption(i)};opts.appendChild(div)});document.getElementById("nextBtn").textContent=cur===total-2?"下一题 (承诺题)":"下一题";document.getElementById("nextBtn").disabled=true;sel=[]}document.getElementById("progress").style.width=(cur/total*100)+"%";document.getElementById("progress").textContent=cur+"/"+total}function selectOption(idx){var q=Q[cur];var opts=document.querySelectorAll(".option");if(q.type==="multiple"){opts[idx].classList.toggle("selected");if(sel.includes(idx)){sel=sel.filter(i=>i!==idx)}else{sel.push(idx)}sel.sort((a,b)=>a-b)}else{opts.forEach(function(el,i){el.classList.toggle("selected",i===idx)});sel=[idx]}document.getElementById("nextBtn").disabled=sel.length===0}function nextQuestion(){if(sel.length===0&&Q[cur].type!=="promise")return;var q=Q[cur];if(q.type!=="promise"){var correctAns=Array.isArray(q.answer)?q.answer:[q.answer];var isCorrect=false;if(q.type==="multiple"){isCorrect=sel.length===correctAns.length&&sel.every(i=>correctAns.includes(i))}else{isCorrect=sel[0]===q.answer}if(isCorrect)corr++}cur++;if(cur>=Q.length){endQuiz();return}showQuestion()}function startTimer(){tmr=setInterval(function(){TL--;var m=Math.floor(TL/60),s=TL%60;document.getElementById("timer").textContent=m+":"+(s<10?"0":"")+s;if(TL<=60)document.getElementById("timer").classList.add("warning");if(TL<=0){clearInterval(tmr);endQuiz()}},1000)}function formatTime(d){return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0")+" "+String(d.getHours()).padStart(2,"0")+":"+String(d.getMinutes()).padStart(2,"0")+":"+String(d.getSeconds()).padStart(2,"0")}function endQuiz(){clearInterval(tmr);endTime=new Date();document.getElementById("quizPage").classList.add("hidden");document.getElementById("resultPage").classList.remove("hidden");var total=Q.length-1;var score=Math.round(corr/total*100);var passed=corr>=Math.ceil(total*CONFIG.quiz.passRate/100);document.getElementById("score").textContent=score+"%";document.getElementById("score").classList.toggle("failed",!passed);if(passed){document.getElementById("passwordBox").classList.remove("hidden");document.getElementById("password").textContent=CONFIG.password}var duration=Math.floor((endTime-startTime)/1000);var min=Math.floor(duration/60),sec=duration%60;document.getElementById("stats").innerHTML='<div class="stats-row"><strong>联系方式:</strong> '+esc(contact)+'<br><strong>游戏名:</strong> '+esc(gameName)+'</div><div class="stats-row"><strong>正确率:</strong> '+score+'% ('+corr+'/'+total+')<br><strong>通过率:</strong> '+CONFIG.quiz.passRate+'%<br><strong>答题时间:</strong> '+min+'分'+sec+'秒<br><strong>结束时间:</strong> '+formatTime(endTime)+'</div><div class="stats-row"><strong>承诺题答案:</strong><div class="promise-answer">'+esc(promiseAnswer||"未填写")+'</div></div>'}</script></body></html>`;
}

export default {
  async fetch(req, env) {
    const url = new URL(req.url);
    const config = env.CONFIG ? JSON.parse(env.CONFIG) : DEFAULT_CONFIG;
    
    if (url.pathname === "/" || url.pathname === "/index.html") {
      return new Response(generateHTML(config), { headers: { "Content-Type": "text/html; charset=utf-8" }});
    }
    
    if (url.pathname === "/api/quiz/start") {
      const basicShuffled = shuffle(BASIC_QUESTIONS);
      const ruleShuffled = shuffle(RULE_QUESTIONS);
      const selected = [
        ...basicShuffled.slice(0, config.quiz.basicCount),
        ...ruleShuffled.slice(0, config.quiz.ruleCount),
        {
          question: "请写下你对服务器的承诺（例如：我将遵守服务器规则，不进行任何作弊行为，尊重其他玩家等）",
          type: "promise",
          placeholder: "请认真写下你的承诺...",
          options: [],
          answer: 0
        }
      ];
      return Response.json({ questions: selected });
    }
    
    return new Response("Not Found", { status: 404 });
  }
};
